```javascript
/**
 * 创建一个 debounce（防抖）函数
 *
 * 在连续调用时，只在最后一次调用后的 wait 毫秒后执行一次。
 *
 * @param {Function} fn      要执行的回调函数
 * @param {number}   wait    等待时间（毫秒）
 * @param {boolean}  [immediate=false] 是否在第一次调用时立即执行
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, wait, immediate = false) {
  let timer = null;
  let lastArgs = null;
  let lastThis = null;

  function debounced(...args) {
    lastArgs = args;
    lastThis = this;

    // 如果已有计时器则清除（重置倒计时）
    if (timer) clearTimeout(timer);

    if (immediate && !timer) {
      // 首次调用且 immediate=true，立即执行
      fn.apply(lastThis, lastArgs);
      lastArgs = null;
      lastThis = null;
    }

    // 设置新的计时器
    timer = setTimeout(() => {
      if (!immediate && lastArgs) {
        fn.apply(lastThis, lastArgs);
      }
      timer = null;
      lastArgs = null;
      lastThis = null;
    }, wait);
  }

  /**
   * 取消防抖，尚未执行的回调将不再触发
   */
  debounced.cancel = function () {
    if (timer) clearTimeout(timer);
    timer = null;
    lastArgs = null;
    lastThis = null;
  };

  /**
   * 立即执行挂起的回调（如果有），并取消防抖
   */
  debounced.flush = function () {
    if (timer && lastArgs) {
      fn.apply(lastThis, lastArgs);
    }
    debounced.cancel();
  };

  return debounced;
}
```

**使用示例：**

```javascript
// 搜索输入框，用户停止输入 300ms 后发起请求
const search = debounce(
  (query) => fetch(`/api/search?q=${query}`),
  300
);

searchInput.addEventListener('input', (e) => search(e.target.value));

// 需要时主动取消防抖
search.cancel();

// 或立刻执行挂起的回调
search.flush();
```

**关键设计点：**

- 每次调用都会重置计时器，只有最后一次调用能真正执行
- 正确处理了 `this` 和参数，适合作为事件监听器
- `immediate` 参数支持"先执行一次，然后等待冷却"的场景（比如提交按钮防连点）
- 暴露了 `cancel` 和 `flush` 方法，给调用方控制权
- 不依赖外部库，纯原生实现

